#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,a[N],p[N],f[N],c[N];

bool cmp(int x,int y){
    if(a[x]==a[y])
        return x<y;
    return a[x]<a[y];
}

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void add(int x,int k){
    for(;x<=n+1;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        p[i]=i;
    }
    for(int i=1;i<=n+1;i++) f[i]=i,c[i]=(i&(-i));
    sort(p+1,p+n+1,cmp);
    int ans=1;
    for(int i=1;i<=n;i++){
        int x=father(i);
        ans=max(ans,ask(x)-1);
        f[p[i]]=father(p[i]+1),add(p[i],-1);
    }
    printf("%d",ans);
    return 0;
}
